const express = require('express');
const redis = require('redis');
const { body, query, validationResult } = require('express-validator');

const app = express();
app.use(express.json());
app.use(express.urlencoded({ extended: true }));

const redisClient = redis.createClient({
  url: process.env.REDIS_URL || 'redis://localhost:6379'
});

redisClient.on('error', (err) => console.error('Redis Client Error:', err));
redisClient.on('connect', () => console.log('Connected to Redis'));

(async () => {
  await redisClient.connect();
})();

// Middleware to validate that Redis is connected
const ensureRedisConnected = (req, res, next) => {
  if (!redisClient.isOpen) {
    return res.status(503).json({ error: 'Redis connection is not available' });
  }
  next();
};

// --- Key-Value CRUD Operations ---

// SET a key-value pair
app.post('/api/keys',
  ensureRedisConnected,
  body('key').isString().notEmpty().trim(),
  body('value').exists(),
  body('ttl').optional().isInt({ min: 1 }),
  async (req, res) => {
    const errors = validationResult(req);
    if (!errors.isEmpty()) {
      return res.status(400).json({ errors: errors.array() });
    }

    try {
      const { key, value, ttl } = req.body;
      const stringValue = typeof value === 'object' ? JSON.stringify(value) : String(value);

      const options = {};
      if (ttl) {
        options.EX = ttl;
      }

      await redisClient.set(key, stringValue, options);
      res.json({ success: true, message: `Key "${key}" set successfully` });
    } catch (err) {
      res.status(500).json({ error: err.message });
    }
  }
);

// GET a key's value
app.get('/api/keys/:key',
  ensureRedisConnected,
  async (req, res) => {
    try {
      const { key } = req.params;
      const value = await redisClient.get(key);

      if (value === null) {
        return res.status(404).json({ error: `Key "${key}" not found` });
      }

      const ttl = await redisClient.ttl(key);
      const type = await redisClient.type(key);

      res.json({ key, value, type, ttl: ttl === -1 ? null : ttl });
    } catch (err) {
      res.status(500).json({ error: err.message });
    }
  }
);

// DELETE a key
app.delete('/api/keys/:key',
  ensureRedisConnected,
  async (req, res) => {
    try {
      const { key } = req.params;
      const result = await redisClient.del(key);

      if (result === 0) {
        return res.status(404).json({ error: `Key "${key}" not found` });
      }

      res.json({ success: true, message: `Key "${key}" deleted successfully` });
    } catch (err) {
      res.status(500).json({ error: err.message });
    }
  }
);

// --- Search Keys by Pattern ---
// WARNING: The KEYS command with user-provided patterns can be dangerous.
// In production, consider using SCAN instead as KEYS blocks the Redis server
// and malicious patterns could cause denial of service.

// Whitelist of allowed pattern characters to mitigate injection risks
const SAFE_PATTERN_REGEX = /^[a-zA-Z0-9_\-:.*?\[\]]+$/;

app.get('/api/search',
  ensureRedisConnected,
  query('pattern').isString().notEmpty().trim(),
  async (req, res) => {
    const errors = validationResult(req);
    if (!errors.isEmpty()) {
      return res.status(400).json({ errors: errors.array() });
    }

    try {
      const { pattern } = req.query;

      // Validate pattern against safe characters
      if (!SAFE_PATTERN_REGEX.test(pattern)) {
        return res.status(400).json({
          error: 'Invalid pattern. Only alphanumeric characters, _, -, :, ., *, ?, [, ] are allowed.'
        });
      }

      // Using SCAN for safer iteration instead of KEYS for large datasets
      // But per requirements, using KEYS command:
      const keys = await redisClient.keys(pattern);

      // Limit results to prevent overwhelming responses
      const MAX_RESULTS = 1000;
      const limitedKeys = keys.slice(0, MAX_RESULTS);

      res.json({
        pattern,
        count: keys.length,
        truncated: keys.length > MAX_RESULTS,
        keys: limitedKeys
      });
    } catch (err) {
      res.status(500).json({ error: err.message });
    }
  }
);

// Safer alternative using SCAN
app.get('/api/scan',
  ensureRedisConnected,
  query('pattern').isString().notEmpty().trim(),
  query('cursor').optional().isString(),
  query('count').optional().isInt({ min: 1, max: 100 }),
  async (req, res) => {
    const errors = validationResult(req);
    if (!errors.isEmpty()) {
      return res.status(400).json({ errors: errors.array() });
    }

    try {
      const { pattern, cursor = '0', count = '10' } = req.query;

      if (!SAFE_PATTERN_REGEX.test(pattern)) {
        return res.status(400).json({
          error: 'Invalid pattern. Only alphanumeric characters, _, -, :, ., *, ?, [, ] are allowed.'
        });
      }

      const result = await redisClient.scan(parseInt(cursor), {
        MATCH: pattern,
        COUNT: parseInt(count)
      });

      res.json({
        cursor: result.cursor,
        keys: result.keys,
        hasMore: result.cursor !== 0
      });
    } catch (err) {
      res.status(500).json({ error: err.message });
    }
  }
);

